from langchain.tools.retriever import create_retriever_tool
from langchain_core.tools import tool
from langchain_openai import ChatOpenAI
from langgraph.prebuilt import create_react_agent

llm = ChatOpenAI(model="gpt-4o", temperature=0)

# Retrieval wrapped as a tool — agent calls it only when needed
policy_tool = create_retriever_tool(
    retriever,
    name="search_policies",
    description=(
        "Search the internal policy documentation. Use this for questions about "
        "return windows, warranty terms, shipping rules, or any internal policy. "
        "Do NOT use for real-time data or calculations."
    ),
)


@tool
def calculate_refund_amount(original_price: float, days_since_purchase: int) -> str:
    """Calculate the exact refund amount based on price and days since purchase."""
    if days_since_purchase <= 30:
        refund = original_price
    elif days_since_purchase <= 60:
        refund = original_price * 0.5
    else:
        refund = 0.0
    return f"Refund amount: ${refund:.2f} ({days_since_purchase} days since purchase)"


agent_with_both = create_react_agent(llm, [policy_tool, calculate_refund_amount])

result = agent_with_both.invoke({
    "messages": [{
        "role": "user",
        "content": "I bought a laptop for $1200 forty days ago. How much refund would I get?"
    }]
})
# Agent calls search_policies for the refund policy, then calculate_refund_amount for the math
print(result["messages"][-1].content)

from langchain_core.tools import tool
from typing import Literal


@tool
def send_email(
    to: str,
    subject: str,
    body: str,
    dry_run: bool = True,  # Default to dry_run — require explicit False to send
) -> str:
    """Send an email. Set dry_run=False to actually send; dry_run=True just previews."""
    if dry_run:
        return (
            f"[DRY RUN] Would send email:\n"
            f"  To: {to}\n  Subject: {subject}\n  Body preview: {body[:100]}..."
        )
    # Production: call your email API (SES, SendGrid, etc.)
    return f"Email sent to {to}: '{subject}'"


@tool
def update_order_status(
    order_id: str,
    new_status: Literal["processing", "shipped", "cancelled"],
    idempotency_key: str,
) -> str:
    """Update an order's status. Idempotency key prevents duplicate updates."""
    # Check if this key was already processed
    if idempotency_key in processed_keys:
        return f"Already processed {idempotency_key} — skipping duplicate."
    processed_keys.add(idempotency_key)
    # Perform the update...
    return f"Order {order_id} updated to '{new_status}'"

processed_keys: set[str] = set()

import time
import hashlib
import json
from functools import wraps
from typing import Callable, Any

# Simple in-process cache — replace with Redis for distributed deployments
_tool_cache: dict[str, tuple[Any, float]] = {}
_CACHE_TTL_SECONDS = 300  # 5-minute TTL for API results


def cached_tool(ttl: int = 300):
    """Decorator that caches tool results by input args for `ttl` seconds."""
    def decorator(fn: Callable) -> Callable:
        @wraps(fn)
        def wrapper(*args, **kwargs):
            key = hashlib.md5(
                json.dumps({"args": args, "kwargs": kwargs}, sort_keys=True).encode()
            ).hexdigest()
            cached, ts = _tool_cache.get(key, (None, 0))
            if cached is not None and (time.time() - ts) < ttl:
                return cached
            result = fn(*args, **kwargs)
            _tool_cache[key] = (result, time.time())
            return result
        return wrapper
    return decorator


def with_retry(max_attempts: int = 3, base_delay: float = 1.0):
    """Retry tool calls on transient failures with exponential backoff."""
    def decorator(fn: Callable) -> Callable:
        @wraps(fn)
        def wrapper(*args, **kwargs):
            for attempt in range(max_attempts):
                try:
                    return fn(*args, **kwargs)
                except Exception as exc:
                    if attempt == max_attempts - 1:
                        raise
                    wait = base_delay * (2 ** attempt)
                    time.sleep(wait)
        return wrapper
    return decorator


